#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int d1 = N % 10;
        int d2 = (N / 10) % 10;
        int d3 = N / 100;
        printf("Digits in reverse order: %d %d %d\n", d1, d2, d3);
    }
    return 0;
}

